-- Migration 012: Clean commercial items + reseed price database with verified market data
-- Generated by scripts/gen_migration_012.py
-- 208 items × 4 regions (MY_KL, MY_PG, MY_JB, SG)

-- ============================================================
-- STEP 1: DELETE commercial/niche categories entirely
-- ============================================================

DELETE FROM price_database WHERE category = 'Commercial Specialty';
DELETE FROM price_database WHERE category = 'Fire Safety';
DELETE FROM price_database WHERE category = 'Signage';

-- ============================================================
-- STEP 2: DELETE commercial subcategories in valid categories
-- ============================================================

DELETE FROM price_database WHERE category = 'Air Conditioning' AND subcategory IN ('Commercial HVAC', 'VRV/VRF System');
DELETE FROM price_database WHERE category = 'Aluminium & Glass' AND subcategory = 'Commercial';
DELETE FROM price_database WHERE category IN ('Aluminium', 'Glass') AND subcategory = 'Commercial';
DELETE FROM price_database WHERE category = 'Carpentry' AND subcategory IN ('Commercial', 'F&B Fitout', 'Office Fitout');
DELETE FROM price_database WHERE category = 'Electrical' AND subcategory IN ('Commercial Electrical', 'Mall Electrical', 'Office Electrical', 'Retail Electrical', 'F&B Electrical', 'Industrial', 'BMS/Building Management');
DELETE FROM price_database WHERE category = 'Flooring' AND subcategory IN ('Commercial', 'Commercial Flooring');
DELETE FROM price_database WHERE category = 'Metal Work' AND subcategory IN ('Commercial', 'Industrial');
DELETE FROM price_database WHERE category = 'Painting' AND subcategory IN ('Commercial', 'F&B Painting', 'Industrial Coating');
DELETE FROM price_database WHERE category = 'Plumbing' AND subcategory IN ('Commercial', 'F&B Plumbing', 'Industrial');
DELETE FROM price_database WHERE category = 'Demolition' AND subcategory IN ('Reinstatement', 'Commercial Demolition');
DELETE FROM price_database WHERE category = 'Construction' AND subcategory IN ('Commercial Construction', 'Mall Construction', 'Industrial Construction');
DELETE FROM price_database WHERE category = 'Security System' AND subcategory IN ('Access Control', 'Mall Security', 'Commercial Security');
DELETE FROM price_database WHERE subcategory = 'Condo Work';
DELETE FROM price_database WHERE category = 'Landscape' AND subcategory IN ('Commercial Landscape', 'Golf Course');

-- ============================================================
-- STEP 3: UPSERT 208 verified seed items (4 regions each)
-- Conflict key: (category, subcategory, material_method, unit, supply_type, region)
-- ============================================================

-- Batch 1 (1–100 of 783 rows)
ON CONFLICT (category, subcategory, material_method, unit, supply_type, region)
DO UPDATE SET min_price = EXCLUDED.min_price, max_price = EXCLUDED.max_price, avg_price = EXCLUDED.avg_price, item_name = EXCLUDED.item_name, confidence = EXCLUDED.confidence, sample_count = EXCLUDED.sample_count;

